const wf = $input.first().json;
console.log(`Actualizando: ${wf.name} (${wf.id})`);
return { json_workflow: wf, log: `OK: ${wf.name}` };

const commit = $node['Webhook'].json.body?.head_commit;
const archivos = commit?.modified?.join(', ') || 'ninguno';
const autor = commit?.author?.name || 'desconocido';
const msg = commit?.message || 'sin mensaje';

return {
  json_workflow: $json.json_workflow,
  commit_sha: commit?.id?.substring(0,7),
  commit_autor: autor,
  commit_msg: msg,
  archivos,
  log: $json.log + ` | Commit ${commit?.id?.substring(0,7)} por ${autor}`
};

parameters.workflowObject:
={{ 
(() => {
  const workflow = JSON.parse(JSON.stringify($json.json_workflow));
  workflow.active = true;

  if (workflow.settings) {
    const allowedSettings = {};
    if (workflow.settings.executionTimeout !== undefined) allowedSettings.executionTimeout = workflow.settings.executionTimeout;
    if (workflow.settings.errorWorkflow !== undefined) allowedSettings.errorWorkflow = workflow.settings.errorWorkflow;
    if (workflow.settings.timezone !== undefined) allowedSettings.timezone = workflow.settings.timezone;
    if (workflow.settings.saveExecutionProgress !== undefined) allowedSettings.saveExecutionProgress = workflow.settings.saveExecutionProgress;
    workflow.settings = allowedSettings;
  }

  return JSON.stringify(workflow);
})() 
}}

parameters.url:
={{ 'https://api.github.com/repos/cristianDev-cmd/workflows_crisdev/contents/' + encodeURIComponent((() => {
  const commit = $node["Webhook"].json.body?.head_commit || {};
  const archivos = [...(commit.modified || []), ...(commit.added || [])];
  return archivos.find(f => f.endsWith('.json')) || 'ninguno.json';
})()) }}

