const base64Content = $input.first().json.content;
if (!base64Content) return $input.first().json;

const buff = Buffer.from(base64Content, 'base64');
const jsonStr = buff.toString('utf8');
const wfObj = JSON.parse(jsonStr);

return wfObj;
